import { Subscription } from "encore.dev/pubsub";
import { workspaceCreatedTopic } from "../platform/events";
import { referralsDB } from "./db";

export const seedReferralData = new Subscription(
  workspaceCreatedTopic,
  "seed-referrals",
  {
    handler: async (event) => {
      await referralsDB.exec`
        INSERT INTO referral_program (workspace_id, reward_points, is_active)
        VALUES (${event.workspaceID}, 500, true)
      `;
    },
  }
);
