import { Subscription } from "encore.dev/pubsub";
import { workspaceCreatedTopic } from "../platform/events";
import { hospitalityDB } from "./db";

// Instead of synchronous API calls, we use event-driven background seeding based directly on Sani engineering principles
export const seedDemoHospitalityData = new Subscription(
  workspaceCreatedTopic,
  "seed-hospitality",
  {
    handler: async (event) => {
      // Create a fake demo property and unit when a workspace is created
      const propRow = await hospitalityDB.queryRow`
        INSERT INTO property (workspace_id, title, location, price, type, amenities, guests, bedrooms, bathrooms, description)
        VALUES (
          ${event.workspaceID}, 
          'The Pine Lodge', 
          'Yellowstone', 
          250, 
          'cabin', 
          '{"wifi", "hot-tub", "fire-pit"}', 
          4, 
          2, 
          1, 
          'Beautiful secluded cabin perfect for small families.'
        )
        RETURNING id
      `;

      await hospitalityDB.exec`
        INSERT INTO unit (property_id, name, status)
        VALUES (${propRow?.id}, 'Cabin A1', 'available')
      `;
    },
  }
);
