export const searchDestinations = api(
  { expose: true, method: "GET", path: "/api/marketplace/search", auth: false },
  async ({ query }: { query: string }) => {
    if (!query || query.trim().length === 0) {
      return { suggestions: [] };
    }

    const q = `%${query}%`;
    const rows = await hospitalityDB.query`
      SELECT DISTINCT 
        location as label, 
        'place' as type 
      FROM property 
      WHERE location ILIKE ${q}
      UNION
      SELECT DISTINCT 
        province as label, 
        'province' as type 
      FROM property 
      WHERE province ILIKE ${q}
      UNION
      SELECT 
        title as label, 
        'listing' as type 
      FROM property 
      WHERE title ILIKE ${q}
      LIMIT 10
    `;

    const suggestions = [];
    for await (const row of rows) {
      suggestions.push(row);
    }

    return { suggestions };
  }
);
