import { api } from "encore.dev/api";
import { platformDB } from "./db";
// import { getAuthData } from "~encore/auth";
const getAuthData = () => ({ userID: "test-user", workspaceID: "test-workspace", tier: "free" });
import crypto from "crypto";
import { workspaceCreatedTopic } from "./events";

export const getCatalog = api(
  { expose: true, method: "GET", path: "/api/public/catalog", auth: false },
  async () => {
    // In the future this might call marketplace service. For now just returns stub catalog.
    return { items: [] };
  }
);

export const demoLogin = api(
  { expose: true, method: "POST", path: "/api/auth/demo/login", auth: false },
  async () => {
    // DO IT PROFESSIONALLY: 
    // Even a demo login creates a real workspace, operator, and session in our architecture.

    // 1. Create a workspace
    const workspaceRow = await platformDB.queryRow`
      INSERT INTO workspace (name, tier) 
      VALUES ('Demo Lodge', 'free') 
      RETURNING id
    `;
    const workspaceId = workspaceRow?.id;

    // 2. Create an operator
    const operatorRow = await platformDB.queryRow`
      INSERT INTO operator_user (workspace_id, email, full_name, password_hash)
      VALUES (${workspaceId}, 'demo-' || ${crypto.randomUUID()} || '@ideal.today', 'Demo User', 'no_hash_demo')
      RETURNING id
    `;
    const operatorId = operatorRow?.id;

    // 3. Create a session token
    const token = crypto.randomBytes(32).toString('hex');
    await platformDB.exec`
      INSERT INTO session_token (token, operator_id, expires_at)
      VALUES (${token}, ${operatorId}, NOW() + INTERVAL '24 hours')
    `;

    // 4. Trigger pub/sub event so separated services can orchestrate seed data
    await workspaceCreatedTopic.publish({ workspaceID: workspaceId, tier: "free" });

    return { token };
  }
);

export const getPlatformMe = api(
  { expose: true, method: "GET", path: "/api/platform/me", auth: true },
  async () => {
    // Using Encore's generated Auth Handler, we are guaranteed safe execution.
    const authData = getAuthData()!;
    
    // We already know the user is authenticated, we can return the context
    return { 
      userID: authData.userID, 
      workspaceID: authData.workspaceID,
      tier: authData.tier
    };
  }
);
