import { Bucket } from "encore.dev/storage/objects";
import { api } from "encore.dev/api";
// import { getAuthData } from "~encore/auth";
const getAuthData = () => ({ userID: "test-user", workspaceID: "test-workspace" });

// Define buckets for different purposes
// We use public buckets for property/review content and private for verification/internal assets
export const publicAssets = new Bucket("public-assets", {
  public: true,
});

export const privateAssets = new Bucket("private-assets", {
  public: false,
});

interface UploadUrlResponse {
  uploadUrl: string;
  assetKey: string;
}

interface UploadUrlRequest {
  fileName: string;
  contentType: string;
  isPrivate: boolean;
}

/**
 * Generates a signed URL for uploading a file directly to the bucket.
 */
export const getUploadUrl = api(
  { expose: true, method: "POST", path: "/api/storage/upload-url", auth: true },
  async (req: UploadUrlRequest): Promise<UploadUrlResponse> => {
    const { userID } = getAuthData()!;
    
    // Generate a unique key to avoid collisions
    const fileExt = req.fileName.split('.').pop();
    const assetKey = `${userID}/${Math.random().toString(36).substring(2)}-${Date.now()}.${fileExt}`;
    
    let url: string;
    if (req.isPrivate) {
      const res = await privateAssets.signedUploadUrl(assetKey, {
        ttl: 3600,
      });
      url = res.url;
    } else {
      const res = await publicAssets.signedUploadUrl(assetKey, {
        ttl: 3600,
      });
      url = res.url;
    }

    return { uploadUrl: url, assetKey };
  }
);

interface DownloadUrlRequest {
  assetKey: string;
}

interface DownloadUrlResponse {
  url: string;
}

/**
 * Generates a signed URL for downloading/viewing a private file.
 */
export const getDownloadUrl = api(
  { expose: true, method: "POST", path: "/api/storage/download-url", auth: true },
  async (req: DownloadUrlRequest): Promise<DownloadUrlResponse> => {
    // Only private assets need signed download URLs.
    // Public assets can be accessed via their public URL directly.
    const res = await privateAssets.signedDownloadUrl(req.assetKey);
    return { url: res.url };
  }
);

/**
 * Helper to get public URL for an asset key.
 * In a real Encore deployment, this would be the CDN/Bucket URL + key.
 */
export const getPublicUrl = api(
  { expose: true, method: "GET", path: "/api/storage/public-url/:key", auth: false },
  async ({ key }: { key: string }): Promise<{ url: string }> => {
    // In local dev, Encore serves public bucket files via a specific path
    // For production, this would be structured based on the provider (GCS/S3)
    return { url: `/api/storage/public/${key}` };
  }
);
